import{_ as t,o as p,c as e,Q as a}from"./chunks/framework.3daba8ea.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/业务框架/DTM/事务消息.md","filePath":"packages/doc/src/业务框架/DTM/事务消息.md","lastUpdated":1702458087000}'),s={name:"doc/业务框架/DTM/事务消息.md"},r=a('<p>总结：</p><p>假设现在有一个本地事务（legion创建学生），两个子事务（bingo创建学生，gauss创建学生），采用事务消息模式</p><p>1.首先创建本地事务不提交，然后执行dtmMsg的prepare方法</p><p>2.如果此时本地事务回滚了，dtm调用反查方法判断要不要继续submit</p><p>3.当反查方法返回fail时，全局事务failed（独立协程做的）</p><p>4.当反查方法成功，继续调用子事务</p><p>5.如果子事务失败会一直重试，每次间隔增大，若程序不能自动修正，需要人工接入</p><p>6.可以直接submit，意味着没有准备阶段，也没有反查方法</p><p>prepare-&gt;反查方法-&gt;submit-&gt;子事务或者（当子事务之前需要做某些操作的时候可以这么干）</p><p>submit-&gt;子事务（简单）</p><p>本地事务修改-&gt;dtmprepare-&gt;本地事务提交-&gt;dtmsubmit-&gt;子事务执行</p><p><strong>概念</strong></p><p>事务消息提供了支持事务的消息接口，允许使用方把消息发送放到本地的一个事务里，保证事务的原子性。它的工作原理如下：</p><p>本地应用</p><ul><li>开启本地事务</li><li>进行本地数据库修改</li><li>调用消息事务的prepare接口，预备发送消息</li><li>提交本地事务</li><li>调用消息事务的submit接口，触发消息发送</li></ul><p>当事务管理器，只收到prepare请求，超时未收到submit请求时，调用反查接口canSubmit，询问应用程序，是否能够发送。</p><p>事务消息与本地消息方案类似，但是将创建本地消息表和轮询本地消息表的操作换成了一个反查接口，提供更加便捷的使用。</p><p>假定一个这样的场景，用户注册成功后，需要给用户赠送优惠券和一个月会员卡。这里赠送优惠券和一个月会员一定不会失败，这种情况就非常适合可靠消息事务模式。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/e785705ef1256dbef5a53aba6c2000bd/xmlnote/3A6B9D8D9D9240D09F89F59754A688CC/30435" alt="0"></p><p>上面的代码首先创建了一个事务消息，然后添加了两个子事务TransOut、TransIn，然后在本地事务里内部调用prepare，本地事务提交之后，调用submit。Submit之后，dtm就会调用相关的子事务，保证最终完成。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/e785705ef1256dbef5a53aba6c2000bd/xmlnote/D35ADB526A44498B8846BA7CE8B6B67A/30438" alt="0"></p>',21),i=[r];function o(c,l,_,d,m,n){return p(),e("div",null,i)}const g=t(s,[["render",o]]);export{b as __pageData,g as default};
